'use client';

import { motion } from 'framer-motion';
import { gsap } from '@/lib/animations/gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { useRef, useEffect } from 'react';
import { Card } from '@/components/ui/card';

export default function About() {
  const sectionRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!sectionRef.current) return;
    gsap.fromTo(
      sectionRef.current.querySelectorAll('.about-item'),
      { y: 50, opacity: 0 },
      {
        y: 0,
        opacity: 1,
        stagger: 0.2,
        duration: 1,
        scrollTrigger: { trigger: sectionRef.current, start: 'top 80%' },
      }
    );
  }, []);

  return (
    <section id="about" ref={sectionRef} className="py-20 md:py-32">
      <div className="container mx-auto px-4">
        <motion.h2 initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} className="about-item text-3xl md:text-4xl font-bold text-center mb-12 gradient-text">
          About Me
        </motion.h2>
        <div className="max-w-3xl mx-auto">
          <Card className="about-item p-8 glass">
            <p className="text-lg text-muted-foreground leading-relaxed">
              I'm a passionate Full Stack Developer with expertise in building modern web applications.
              My journey in tech started with curiosity and has evolved into a career crafting
              performant, user-centric digital experiences. I specialize in React, Next.js, Node.js,
              and cloud technologies.
            </p>
          </Card>
        </div>
      </div>
    </section>
  );
}
